    'DisplayName', 'NACA 4415 (reference)');
plot(xq_n, yn_ui, '-', 'Color', [0.50 0.65 0.85], 'LineWidth', 1.2, 'HandleVisibility', 'off');
plot(xq_n, yn_li, '-', 'Color', [0.50 0.65 0.85], 'LineWidth', 1.2, 'HandleVisibility', 'off');

% Final Optimised profile outline
opt_x_plot = [flip(xu_opt); xl_opt(2:end)];
opt_y_plot = [flip(yu_opt); yl_opt(2:end)];
plot(opt_x_plot, opt_y_plot, 'k-', 'LineWidth', 3, ...
    'DisplayName', 'Final Optimised Profile');

% Mean camber line
plot(xq, ymcl, 'r--', 'LineWidth', 2, ...
    'DisplayName', 'Mean Camber Line');

% Max camber marker
plot(xq(idxC), maxC, 'ro', ...
    'MarkerFaceColor', 'r', 'MarkerSize', 9, ...
    'DisplayName', sprintf('Max Camber: %.2f mm (%.1f%% c)', maxC, xq(idxC)/chord*100));

% Max thickness marker
plot([xq(idxT) xq(idxT)], [yl_i(idxT) yu_i(idxT)], 'b-s', ...
    'LineWidth', 2, 'MarkerFaceColor', 'b', 'MarkerSize', 8, ...
    'DisplayName', sprintf('Max Thickness: %.2f mm (%.1f%% c)', maxT, xq(idxT)/chord*100));

% -------------------------------------------------------------------------
% Formatting
% -------------------------------------------------------------------------
axis equal;
xlim([-15, chord + 15]);
ylim([-chord*0.15, chord*0.35]);

lgd = legend('Location', 'northwest', 'FontSize', 15, 'FontWeight', 'bold');
title(lgd, sprintf('Chord = %.0f mm', chord));
set(lgd, 'Box', 'on', 'EdgeColor', 'k', 'Color', [1 1 1 0.88]);

set(gca, 'FontSize', 18, 'FontWeight', 'bold', 'LineWidth', 1.5, 'XColor', 'k', 'YColor', 'k');
xlabel('Chordwise Position [mm]',  'FontSize', 18, 'FontWeight', 'bold');
ylabel('Thickness / Camber [mm]',  'FontSize', 18, 'FontWeight', 'bold');
title('Final Optimised Aerofoil Geometry', 'FontSize', 22, 'Color', 'k', 'FontWeight', 'bold');

hold off;